  "cases": [
    {
      "input": {
        "enable": [
          "track"
        ],
        "triggers": [
          {
            "package": "acme/orm",
            "link": "https://dep.example.com/orm/1234",
            "message": "this is deprecated %s %d",
            "args": [
              "foo",
              1234
            ]
          }
        ],
        "disable_after": true
      },
      "expected_output": "unique_count=0\ncount[https://dep.example.com/orm/1234]=0\n"
    }
  ]
}
